def parse_run_block(self) -> str:
    """Parse run block - contains raw shell commands."""
    self.expect(TokenType.LBRACE)
    # Collect all content until matching }
    depth = 1
    lines = []
    current_line = []

    while depth > 0:
        if self.match(TokenType.EOF):
            self.error("Unterminated run block")

        token = self.current()

        if token.type == TokenType.LBRACE:
            depth += 1
            current_line.append('{')
            self.advance()
        elif token.type == TokenType.RBRACE:
            depth -= 1
            if depth > 0:
                current_line.append('}')
            self.advance()
        elif token.type == TokenType.STRING:
            # Preserve quotes around strings
            current_line.append(f'"{token.value}"')
            self.advance()
        elif token.type == TokenType.DOLLAR:
