                result_lines.append('')
                self.advance()
                continue

            # Build the line from tokens
            line_parts = []
            while not self.match(TokenType.NEWLINE) and not self.match(TokenType.RBRACE) and not self.match(TokenType.EOF):
                token = self.current()

                if token.type == TokenType.STRING:
                    # Preserve quotes around strings
                    line_parts.append(f'"{token.value}"')
                elif token.type == TokenType.DOLLAR:
                    line_parts.append(token.value)
                elif token.type == TokenType.IDENTIFIER:
                    line_parts.append(token.value)
                elif token.type == TokenType.INT:
                    line_parts.append(str(token.value))
                elif token.type == TokenType.FLOAT:
                    line_parts.append(str(token.value))
                elif token.type == TokenType.COLON:
                    line_parts.append(':')
                elif token.type == TokenType.SEMICOLON:
                    line_parts.append(';')
                elif token.type == TokenType.COMMA:
                    line_parts.append(',')
                elif token.type == TokenType.DOT:
                    line_parts.append('.')
                elif token.type == TokenType.LPAREN:
                    line_parts.append('(')
                elif token.type == TokenType.RPAREN:
                    line_parts.append(')')
                elif token.type == TokenType.LBRACE:
                    line_parts.append('{')
