                    line_parts.append('*')
                elif token.type == TokenType.SLASH:
                    line_parts.append('/')
                elif token.type == TokenType.PERCENT:
                    line_parts.append('%')
                elif token.type == TokenType.EQUALS:
                    line_parts.append('=')
                elif token.type == TokenType.EQ:
                    line_parts.append('==')
                elif token.type == TokenType.NEQ:
                    line_parts.append('!=')
