            return 'string'
        elif self.match(TokenType.INT_TYPE):
            self.advance()
            return 'int'
        elif self.match(TokenType.FLOAT_TYPE):
            self.advance()
            return 'float'
        elif self.match(TokenType.BOOL_TYPE):
            self.advance()
            return 'bool'
        elif self.match(TokenType.LIST_TYPE):
            self.advance()
            return 'list'
        else:
            self.error(f"Expected type name, got {self.current().type}")

